Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  // Admin authorization check
  const authHeader = req.headers.get("Authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }

  const anonClient = createClient(
    Deno.env.get("SUPABASE_URL")!,
    Deno.env.get("SUPABASE_ANON_KEY")!,
    { global: { headers: { Authorization: authHeader } } }
  );

  const token = authHeader.replace("Bearer ", "");
  const { data: claimsData, error: claimsError } = await anonClient.auth.getClaims(token);
  if (claimsError || !claimsData?.claims) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }

  const adminEmails = (Deno.env.get("ADMIN_EMAIL") || "").split(",").map((e: string) => e.trim().toLowerCase());
  const userEmail = (claimsData.claims.email as string || "").toLowerCase();
  if (!adminEmails.includes(userEmail)) {
    return new Response(JSON.stringify({ error: "Forbidden: admin access required" }), {
      status: 403,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }

  const supabase = createClient(
    Deno.env.get("SUPABASE_URL")!,
    Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!
  );

  try {
    // Clear existing data
    await supabase.from("fish_species").delete().neq("id", "00000000-0000-0000-0000-000000000000");
    await supabase.from("fishing_locations").delete().neq("id", "00000000-0000-0000-0000-000000000000");

    // Insert fish in batches of 100
    for (let i = 0; i < fishSpecies.length; i += 100) {
      const batch = fishSpecies.slice(i, i + 100);
      const { error } = await supabase.from("fish_species").insert(batch);
      if (error) throw new Error(`Fish batch ${i}: ${error.message}`);
    }

    // Insert locations in batches of 100
    for (let i = 0; i < fishingLocations.length; i += 100) {
      const batch = fishingLocations.slice(i, i + 100);
      const { error } = await supabase.from("fishing_locations").insert(batch);
      if (error) throw new Error(`Location batch ${i}: ${error.message}`);
    }

    return new Response(
      JSON.stringify({
        success: true,
        fish_count: fishSpecies.length,
        location_count: fishingLocations.length,
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    return new Response(
      JSON.stringify({ error: error.message }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});
